  #   AFTER_ALL_TXS -> afterAllTxs
  # But Swift uses .afterAllTx (no trailing 's')
  # =========================================================================
  "TransactionEventStage" => {
    "TRANSACTION_EVENT_STAGE_AFTER_ALL_TXS" => "afterAllTx",
  },

  # =========================================================================
  # TransactionMetaType (internal name, not in canonical XDR as named enum)
  # This is the discriminant for TransactionMeta union (uses int v)
  # Swift: .operations=0, .transactionMetaV1=1, .transactionMetaV2=2,
  #        .transactionMetaV3=3, .transactionMetaV4=4
  # These are SDK-specific names, not derivable from XDR.
  # The union uses plain int discriminant (0, 1, 2, 3, 4).
  # =========================================================================

  # =========================================================================
  # ContractDataDurability
  # XDR: TEMPORARY=0, PERSISTENT=1
  # Swift: .temporary, .persistent
  # Mechanical: lowercase first letter. All match.
  # =========================================================================

  # =========================================================================
  # Result code enums: these all follow the same pattern.
  # XDR member names have the enum type as prefix.
  # Swift names strip the prefix and use camelCase.
  # The mechanical conversion handles these correctly.
  #
  # Verified for: CreateAccountResultCode, PaymentResultCode,
  # PathPaymentStrictReceiveResultCode (mapped to PathPaymentResultCode),
  # PathPaymentStrictSendResultCode (mapped to PathPaymentResultCode),
  # ManageSellOfferResultCode (mapped to ManageOfferResultCode),
  # ManageBuyOfferResultCode (mapped to ManageOfferResultCode),
  # SetOptionsResultCode, ChangeTrustResultCode, AllowTrustResultCode,
  # AccountMergeResultCode, InflationResultCode, ManageDataResultCode,
  # BumpSequenceResultCode, CreateClaimableBalanceResultCode,
  # ClaimClaimableBalanceResultCode, BeginSponsoringFutureReservesResultCode,
  # EndSponsoringFutureReservesResultCode, RevokeSponsorshipResultCode,
  # ClawbackResultCode, ClawbackClaimableBalanceResultCode,
  # SetTrustLineFlagsResultCode, LiquidityPoolDepositResultCode,
  # LiquidityPoolWithdrawResultCode, InvokeHostFunctionResultCode,
  # ExtendFootprintTTLResultCode, RestoreFootprintResultCode
  # =========================================================================

  # =========================================================================
  # UNION ARM NAME OVERRIDES
  #
  # These map XDR union arm variable names (as produced by xdrgen) to the
  # case names used in the current iOS SDK. The key is the arm variable name
  # from the .x file (camelCased), the value is the current SDK case name.
  #
  # The generator checks MEMBER_OVERRIDES[UnionTypeName][armVarName] when
  # deriving Swift case names for non-void union arms.
  # =========================================================================

  # AllowTrustOpAssetXDR -- SDK uses "alphanum4/alphanum12" instead of "assetCode4/assetCode12"
  "AllowTrustOpAssetXDR" => {
    "assetCode4"  => "alphanum4",
    "assetCode12" => "alphanum12",
  },

  # ClaimPredicateXDR -- SDK uses discriminant-style names, not arm var names
  "ClaimPredicateXDR" => {
    "andPredicates" => "claimPredicateAnd",
    "orPredicates"  => "claimPredicateOr",
    "notPredicate"  => "claimPredicateNot",
    "absBefore"     => "claimPredicateBeforeAbsTime",
    "relBefore"     => "claimPredicateBeforeRelTime",
  },

  # PreconditionsXDR -- SDK uses "time" instead of "timeBounds"
  "PreconditionsXDR" => {
    "timeBounds" => "time",
  },

  # MemoXDR -- SDK uses "none" for void arm, "returnHash" instead of "retHash"
  "MemoXDR" => {
    "MEMO_TYPE_NONE" => "none",
    "retHash"        => "returnHash",
  },

  # AssetXDR -- SDK uses lowercase "alphanum" instead of camelCase "alphaNum"
  "AssetXDR" => {
    "alphaNum4"  => "alphanum4",
    "alphaNum12" => "alphanum12",
  },

  # SignerKeyXDR -- SDK uses "signedPayload" instead of "ed25519SignedPayload"
  "SignerKeyXDR" => {
    "ed25519SignedPayload" => "signedPayload",
  },

  # ClaimantXDR -- SDK uses discriminant-style "claimantTypeV0" instead of "v0"
  "ClaimantXDR" => {
    "v0" => "claimantTypeV0",
  },

  # ClaimableBalanceIDXDR -- SDK uses "claimableBalanceIDTypeV0" instead of "v0"
  "ClaimableBalanceIDXDR" => {
    "v0" => "claimableBalanceIDTypeV0",
  },

  # LedgerKeyXDR -- SDK uses lowercase "trustline" instead of "trustLine"
  "LedgerKeyXDR" => {
    "trustLine" => "trustline",
  },

  # TransactionMetaXDR -- SDK uses "transactionMetaV1/V2/V3/V4" instead of "v1/v2/v3/v4"
  "TransactionMetaXDR" => {
    "v1" => "transactionMetaV1",
    "v2" => "transactionMetaV2",
    "v3" => "transactionMetaV3",
    "v4" => "transactionMetaV4",
  },

  # HashIDPreimageXDR -- SDK uses lowercase "Id" instead of uppercase "ID"
  "HashIDPreimageXDR" => {
    "operationID" => "operationId",
    "revokeID"    => "revokeId",
  },

  # ChangeTrustAssetXDR -- SDK uses lowercase "alphanum" and "poolShare"
  "ChangeTrustAssetXDR" => {
    "alphaNum4"     => "alphanum4",
    "alphaNum12"    => "alphanum12",
    "liquidityPool" => "poolShare",
  },

  # TrustlineAssetXDR -- SDK uses lowercase "alphanum" and "poolShare"
  "TrustlineAssetXDR" => {
    "alphaNum4"       => "alphanum4",
    "alphaNum12"      => "alphanum12",
    "liquidityPoolID" => "poolShare",
  },

  # ContractExecutableXDR -- SDK uses "wasm" and "token" instead of
  # "wasmHash" and "stellarAsset"
  "ContractExecutableXDR" => {
    "wasmHash"     => "wasm",
    "stellarAsset" => "token",
  },

  # HostFunctionXDR -- SDK uses "uploadContractWasm" instead of "wasm"
  "HostFunctionXDR" => {
    "wasm" => "uploadContractWasm",
  },

  # RevokeSponsorshipOpXDR -- SDK uses discriminant-style names
  "RevokeSponsorshipOpXDR" => {
    "ledgerKey" => "revokeSponsorshipLedgerEntry",
    "signer"    => "revokeSponsorshipSignerEntry",
  },

  # TransactionExtXDR -- SDK uses "sorobanTransactionData" instead of "sorobanData"
  "TransactionExtXDR" => {
    "sorobanData" => "sorobanTransactionData",
  },

  # BinaryFuseFilterType -- Swift can't have case names starting with digits
  "BinaryFuseFilterType" => {
    "BINARY_FUSE_FILTER_8_BIT"  => "eightBit",
    "BINARY_FUSE_FILTER_16_BIT" => "sixteenBit",
    "BINARY_FUSE_FILTER_32_BIT" => "thirtyTwoBit",
  },

  # LedgerEntryDataXDR -- SDK uses lowercase "trustline"
  "LedgerEntryDataXDR" => {
    "trustLine" => "trustline",
  },

  # SCAddressXDR -- SDK uses "account" and "contract" instead of
  # "accountId" and "contractId"
  "SCAddressXDR" => {
    "accountId"  => "account",
    "contractId" => "contract",
  },

  # SCSpecEntryXDR -- SDK strips "udt" prefix from arm names
  "SCSpecEntryXDR" => {
    "udtStructV0"    => "structV0",
    "udtUnionV0"     => "unionV0",
    "udtEnumV0"      => "enumV0",
    "udtErrorEnumV0" => "errorEnumV0",
  },

  # SCSpecUDTUnionCaseV0XDR -- SDK uses "voidV0/tupleV0" instead of
  # "voidCase/tupleCase"
  "SCSpecUDTUnionCaseV0XDR" => {
    "voidCase"  => "voidV0",
    "tupleCase" => "tupleV0",
  },

  # AccountEntryExtXDR -- SDK uses "accountEntryExtensionV1" instead of "v1"
  "AccountEntryExtXDR" => {
    "v1" => "accountEntryExtensionV1",
  },

  # AccountEntryExtensionV1ExtXDR -- SDK uses "accountEntryExtensionV2"
  # Note: This type is named AccountEntryExtV1XDR in the name_overrides
  # (XDR name: AccountEntryExtV1)
  "AccountEntryExtV1XDR" => {
    "v2" => "accountEntryExtensionV2",
  },

  # AccountEntryExtensionV2ExtXDR -- SDK uses "accountEntryExtensionV3"
  # Note: This type is named AccountEntryExtV2XDR in the name_overrides
  # (XDR name: AccountEntryExtV2)
  "AccountEntryExtV2XDR" => {
    "v3" => "accountEntryExtensionV3",
  },

  # TrustlineEntryExtXDR -- SDK uses "trustlineEntryExtensionV1"
  "TrustlineEntryExtXDR" => {
    "v1" => "trustlineEntryExtensionV1",
  },

  # TrustlineEntryExtV1XDR -- SDK uses "trustlineEntryExtensionV2"
  # Note: This type is named TrustlineEntryExtV1XDR in the name_overrides
  # (XDR name: TrustLineEntryExtV1)
  "TrustlineEntryExtV1XDR" => {
    "v2" => "trustlineEntryExtensionV2",
  },

  # ClaimableBalanceEntryExtXDR -- SDK uses "claimableBalanceEntryExtensionV1"
  "ClaimableBalanceEntryExtXDR" => {
    "v1" => "claimableBalanceEntryExtensionV1",
  },

  # LedgerEntryExtXDR -- SDK uses "ledgerEntryExtensionV1"
  "LedgerEntryExtXDR" => {
    "v1" => "ledgerEntryExtensionV1",
  },

}.freeze
